import { Injectable } from '@angular/core';
import { BaseService } from './Base/base.service';
import { UserPromotion } from '../customer/user-promotions/user-promotions.component';

export type SendErrorCode = 'already_sent' | 'weekly_limit' | 'no_recipients' | 'unknown';

@Injectable({ providedIn: 'root' })
export class PromotionNotificationService extends BaseService<any> {
  protected getTableName(): string {
    return 'promotion_notifications';
  }

  async daysUntilNextAllowed(): Promise<number> {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return 0;

    const { data } = await this.getSupabaseClientPublic()
      .from(this.getTableName())
      .select('sent_at')
      .eq('restaurant_id', restaurantId)
      .order('sent_at', { ascending: false })
      .limit(1);

    if (!data || data.length === 0) return 0;

    const lastSent = new Date(data[0].sent_at);
    const diffDays = Math.ceil((Date.now() - lastSent.getTime()) / (1000 * 60 * 60 * 24));

    return diffDays >= 7 ? 0 : 7 - diffDays;
  }

  async hasBeenNotified(promotionId: string): Promise<boolean> {
    const restaurantId = await this.getCurrentRestaurantId();
    if (!restaurantId) return false;

    const { data } = await this.getSupabaseClientPublic()
      .from(this.getTableName())
      .select('id')
      .eq('promotion_id', promotionId)
      .eq('restaurant_id', restaurantId)
      .limit(1);

    return (data?.length ?? 0) > 0;
  }

async sendPromotionPush(promotionId: string): Promise<{ success: boolean; sent?: number; errorCode?: SendErrorCode; message?: string }> {
  const restaurantId = await this.getCurrentRestaurantId();
  if (!restaurantId) return { success: false, errorCode: 'unknown', message: 'Ristorante non trovato' };

  // 1. Ottieni i follower del ristorante
  const { data: followers, error: followersError } = await this.getSupabaseClientPublic()
    .from('restaurant_followers')
    .select('user_id')
    .eq('restaurant_id', restaurantId);

  if (followersError || !followers?.length) {
    return { success: false, errorCode: 'no_recipients', message: 'Nessun follower' };
  }

  const followerIds = followers.map(f => f.user_id);

  // 2. Ottieni le push subscription attive per questi follower
  const { data: subscriptions, error: subError } = await this.getSupabaseClientPublic()
    .from('push_subscriptions')
    .select('user_id')
    .eq('is_active', true)
    .in('user_id', followerIds);

  if (subError || !subscriptions?.length) {
    return { success: false, errorCode: 'no_recipients', message: 'Nessun follower con notifiche attive' };
  }

  // 3. Inserisci una notifica per ogni utente (raggruppati per user_id per evitare duplicati se più dispositivi)
  const uniqueUserIds = [...new Set(subscriptions.map(s => s.user_id))];
  
  const notifications = uniqueUserIds.map(userId => ({
    promotion_id: promotionId,
    restaurant_id: restaurantId,
    user_id: userId,
    channel: 'push',
    status: 'sent',
    sent_at: new Date().toISOString(),
  }));

  const { error: insertError } = await this.getSupabaseClientPublic()
    .from('promotion_notifications')
    .insert(notifications);

  if (insertError) {
    console.error('Errore inserimento notifiche:', insertError);
    return { success: false, errorCode: 'unknown', message: 'Errore durante il salvataggio' };
  }

  return { success: true, sent: uniqueUserIds.length };
}

async getMyPromotions(): Promise<UserPromotion[]> {
  const userId = this.authService.currentUserValue?.id;
  if (!userId) return [];

  const { data, error } = await this.getSupabaseClientPublic()
    .from('promotion_notifications')
    .select(`
      id,
      sent_at,
      promotion:promotions!inner (
        id,
        name,
        description,
        image_url,
        type,
        discount_value,
        max_discount_amount,
        valid_from,
        valid_until,
        min_order_amount
      ),
      restaurant:restaurants!inner (
        id,
        name,
        logo_url
      )
    `)
    .eq('user_id', userId)
    .order('sent_at', { ascending: false });

  if (error) {
    console.error('Errore nel recupero promozioni utente:', error);
    return [];
  }

  // Trasforma i dati: prendi il primo elemento se è un array
  return (data || []).map(item => ({
    notification_id: item.id,
    sent_at: item.sent_at,
    promotion: Array.isArray(item.promotion) ? item.promotion[0] : item.promotion,
    restaurant: Array.isArray(item.restaurant) ? item.restaurant[0] : item.restaurant
  }));
}

}